const crypto = require('crypto');

const employeeId = $json.body.employeeId;

// Chercher la ligne correspondante dans Google Sheets
// $json contient toutes les lignes du sheet
const rows = $json;
let found = null;

// Format attendu: [employeeId, credentialId, publicKey, transports, createdAt]
for (const row of rows) {
  // row est un tableau si dataMode=nothing
  if (Array.isArray(row) && row[0] === employeeId) {
    found = {
      employeeId: row[0],
      credentialId: row[1],
      publicKey: row[2],
      transports: row[3]
    };
    break;
  }
  // row est un objet si structured data
  if (row && typeof row === 'object' && (row.employeeId === employeeId || row[0] === employeeId)) {
    found = {
      employeeId: row.employeeId || row[0],
      credentialId: row.credentialId || row[1],
      publicKey: row.publicKey || row[2],
      transports: row.transports || row[3]
    };
    break;
  }
}

if (!found) {
  return {
    success: false,
    error: "Aucune clé biométrique trouvée pour cet employé. Enregistrez d'abord votre visage."
  };
}

// Générer un nouveau challenge (32 bytes)
const challenge = crypto.randomBytes(32).toString('base64url');

return {
  success: true,
  challenge: challenge,
  credentialId: found.credentialId,
  publicKey: found.publicKey,
  transports: found.transports ? JSON.parse(found.transports) : ['internal'],
  rpId: $json.body.rpId || 'localhost',
  employeeId: employeeId
};

const crypto = require('crypto');

const body = $json.body;

// --- Extraire les données ---
const challenge = body.challenge;
const credentialId = body.credentialId;
const clientDataJSON = body.clientDataJSON;  // base64url
const authenticatorData = body.authenticatorData;  // base64url
const signature = body.signature;  // base64url
const employeeId = body.employeeId;

// --- Récupérer la clé publique depuis le résultat GS ---
// Le résultat Google Sheets est dans $node["📊 GS — Chercher clé"].data
const gsResult = $node["📊 GS — Chercher clé"].data;

let publicKeyB64 = null;
let storedTransports = '[]';

// Parcourir les lignes pour trouver la bonne
for (const item of (Array.isArray(gsResult) ? gsResult : [gsResult])) {
  if (Array.isArray(item)) {
    if (item[1] === credentialId) {
      publicKeyB64 = item[2];
      storedTransports = item[3] || '[]';
      break;
    }
  } else if (item && typeof item === 'object') {
    if ((item.credentialId || item[1]) === credentialId) {
      publicKeyB64 = item.publicKey || item[2];
      storedTransports = item.transports || item[3] || '[]';
      break;
    }
  }
}

if (!publicKeyB64) {
  return { success: false, error: 'Clé publique introuvable pour ce credential' };
}

// --- Décoder la clé publique COSE en JWK ---
// Format stocké: COSE_Key bytes encodés en base64url
const coseBuffer = Buffer.from(publicKeyB64, 'base64url');

// Parser COSE EC2 key
// Structure: [tag] [1:kty] [3:alg] [-1:crv] [-2:x] [-3:y]
// Pour ES256 (P-256):
//   kty = 2 (EC2)
//   alg = -7 (ES256)
//   crv = 1 (P-256)
//   x = 32 bytes
//   y = 32 bytes
// Format CBOR map

function parseCOSEKey(buffer) {
  // CBOR decoder minimal pour COSE EC2
  // Format attendu: map de 5 paires
  let offset = 0;

  // Lire le premier byte pour déterminer le type
  const firstByte = buffer[offset];

  // CBOR map: 0xA5 = map(5), 0xA4 = map(4)
  if ((firstByte & 0xE0) !== 0xA0) {
    throw new Error('Expected CBOR map at start, got: 0x' + firstByte.toString(16));
  }

  const mapLen = firstByte & 0x1F;
  offset++;

  const map = {};
  for (let i = 0; i < mapLen; i++) {
    // Lire la clé
    const keyType = buffer[offset] & 0xE0;
    let key;
    if ((buffer[offset] & 0xE0) === 0x20) {
      // Negative integer
      key = -((buffer[offset] & 0x1F) + 1);
      offset++;
    } else if ((buffer[offset] & 0xE0) === 0x00) {
      // Unsigned integer
      key = buffer[offset] & 0x1F;
      offset++;
    } else {
      throw new Error('Unexpected key type at offset ' + offset);
    }

    // Lire la valeur
    if (key < 0) {
      // Negative keys are byte strings
      if (buffer[offset] === 0x58) {
        // byte string avec longueur 1-byte
        const len = buffer[offset + 1];
        map[key] = buffer.slice(offset + 2, offset + 2 + len);
        offset += 2 + len;
      } else if ((buffer[offset] & 0xE0) === 0x40) {
        // byte string simple
        const len = buffer[offset] & 0x1F;
        map[key] = buffer.slice(offset + 1, offset + 1 + len);
        offset += 1 + len;
      } else if (buffer[offset] === 0x59) {
        // byte string avec longueur 2-bytes
        const len = buffer.readUInt16BE(offset + 1);
        map[key] = buffer.slice(offset + 3, offset + 3 + len);
        offset += 3 + len;
      } else {
        throw new Error('Unexpected value type for key ' + key + ' at offset ' + offset);
      }
    } else {
      // Positive keys are integers
      if ((buffer[offset] & 0xE0) === 0x00) {
        map[key] = buffer[offset] & 0x1F;
        offset++;
      } else if (buffer[offset] === 0x18) {
        map[key] = buffer[offset + 1];
        offset += 2;
      } else if (buffer[offset] === 0x19) {
        map[key] = buffer.readUInt16BE(offset + 1);
        offset += 3;
      } else if (buffer[offset] === 0x1A) {
        map[key] = buffer.readUInt32BE(offset + 1);
        offset += 5;
      } else if (buffer[offset] === 0x20) {
        // negative int simple
        map[key] = -(buffer[offset] & 0x1F) - 1;
        offset++;
      } else if (buffer[offset] === 0x38) {
        map[key] = -(buffer[offset + 1]) - 1;
        offset += 2;
      } else {
        throw new Error('Unexpected value type for key ' + key + ' at offset ' + offset);
      }
    }
  }

  return map;
}

let coseKey;
try {
  coseKey = parseCOSEKey(coseBuffer);
} catch (e) {
  // Fallback: si le format n'est pas CBOR, essayer de traiter comme du JSON
  try {
    coseKey = JSON.parse(publicKeyB64);
  } catch (e2) {
    return { success: false, error: 'Format de clé invalide: ' + e.message };
  }
}

// Extraire x et y
const xBytes = coseKey[-2];
const yBytes = coseKey[-3];

if (!xBytes || !yBytes) {
  return { success: false, error: 'Coordonnées de clé manquantes (x ou y)' };
}

// Convertir en JWK
const jwk = {
  kty: 'EC',
  crv: 'P-256',
  x: Buffer.from(xBytes).toString('base64url'),
  y: Buffer.from(yBytes).toString('base64url'),
};

// --- Importer la clé publique ---
let publicKey;
try {
  publicKey = crypto.createPublicKey({ key: jwk, format: 'jwk' });
} catch (e) {
  return { success: false, error: 'Erreur import clé: ' + e.message };
}

// --- Reconstruire les données signées ---
const authDataBuf = Buffer.from(authenticatorData, 'base64url');
const clientDataBuf = Buffer.from(clientDataJSON, 'base64url');
const clientDataHash = crypto.createHash('sha256').update(clientDataBuf).digest();
const signedData = Buffer.concat([authDataBuf, clientDataHash]);

// --- Vérifier la signature ---
const sigBuf = Buffer.from(signature, 'base64url');

let verified;
try {
  verified = crypto.verify(
    undefined,  // utilise l'algorithme de la clé
    signedData,
    publicKey,
    sigBuf
  );
} catch (e) {
  return { success: false, error: 'Erreur vérification: ' + e.message };
}

if (!verified) {
  return { success: false, error: '❌ Visage non reconnu' };
}

// ✅ Vérification réussie !
return {
  success: true,
  verified: true,
  employeeId: employeeId,
  credentialId: credentialId,
  message: '✅ Visage vérifié avec succès'
};

// Fusionner la réponse du forward avec la vérification
const verifyResult = $node["✅ Vérifier Signature"].json;
const forwardResponse = $json;

return {
  success: true,
  verified: true,
  biometricsVerified: true,
  employeeId: verifyResult.employeeId,
  forwardResponse: forwardResponse,
  message: '✅ Pointage + biométrie validés'
};
